func solve(grid [][]int64, x int64, y int64, k int64) [][]int64 {
    // Create a copy of the grid to avoid modifying the original
    result := make([][]int64, len(grid))
    for i := range grid {
        result[i] = make([]int64, len(grid[i]))
        copy(result[i], grid[i])
    }

    // Extract the submatrix
    submatrix := make([][]int64, k)
    for i := 0; i < k; i++ {
        submatrix[i] = make([]int64, k)
        for j := 0; j < k; j++ {
            submatrix[i][j] = result[x+i][y+j]
        }
    }

    // Reverse the submatrix
    for i := 0; i < k/2; i++ {
        submatrix[i], submatrix[k-1-i] = submatrix[k-1-i], submatrix[i]
    }

    // Replace the original submatrix with the reversed one
    index := 0
    for i := x; i < x+k; i++ {
        for j := y; j < y+k; j++ {
            result[i][j] = submatrix[index][j - y]
            index++
        }
    }

    return result
}
